{
  "mode": "All",
  "policyRule": {
    "if": {
      "allOf": [
        { "field": "type", "equals": "Microsoft.AAD/applications" },
        { "field": "Microsoft.AAD/applications/passwordCredentials[*].endDateTime", "exists": true }
      ]
    },
    "then": { "effect": "deny" }
  }
}
